import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';

import { addRow } from '../../consts/crud';
import { handleLogout } from '../../consts/handleLogout';

import '../../App.css';
import '../../../node_modules/bootstrap/dist/css/bootstrap.css'


function AddTypeCrossroad() {
    const [type_crossroad, setTypeCrossroad] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const submitTypeCrossroad = async (e) => {
        const headers = null;
        const typeCrossroad = { type_crossroad };

        setLoading(true);
        e.preventDefault();
        addRow('/type_crossroads', typeCrossroad, headers);
        setTypeCrossroad('');
        navigate('/type_crossroads');
        setLoading(false);
    };

    return (
        <div>
            <nav className="navbar navbar-expand-lg navbar-dark bg-dark flex-column align-items-start p-0">
                <div className="container-fluid py-2">
                    <Link className="navbar-brand fs-3 fw-bold" to="/main">Дорожное хозяйство</Link>
                    <div class="btn-group">
                        <button type="button" class="btn btn-info">{ localStorage.getItem('login') }</button>
                        <button type="button" class="btn btn-info dropdown-toggle dropdown-toggle-split" data-bs-toggle="dropdown" aria-expanded="false">
                            <span class="visually-hidden">Переключатель выпадающего списка</span>
                        </button>
                        <ul class="dropdown-menu">
                            <li>
                                <a class="dropdown-item">
                                    <button
                                        onClick={() => { handleLogout(localStorage.getItem('id')); navigate('/login') }} 
                                        className='dropdown-item'
                                        disabled={loading}
                                    >
                                        {loading ? (
                                            <>
                                                <span className='spinner'></span>
                                                Выход...
                                            </>
                                        ) : 'Выйти'}
                                    </button>
                                </a>
                            </li>
                        </ul>
                    </div>
                </div>
            </nav>
            <form className='container' onSubmit={submitTypeCrossroad}>
                <h1>Создание типа перекрестка.</h1>
                <div className='mb-3'>
                    <lable className='form-label'>Тип перекрестка</lable>
                    <input 
                        type='text'
                        name='type_crossroad' 
                        value={type_crossroad.type_crossroad} 
                        onChange={(e) => setTypeCrossroad(e.target.value)}
                        className='form-input'  
                        placeholder='type_crossroad'
                        required  
                    />
                </div>
                <button 
                    type='submit' 
                    className='btn btn-primary'
                >
                    Добавить
                </button>
                <button 
                    type='submit' 
                    className='btn btn-danger' 
                    onClick={() => navigate('/type_crossroads')}
                >
                    Назад
                </button>
            </form>
        </div>
    )

};

export default AddTypeCrossroad;
